# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Threading.Tasks;

namespace YourNamespace.Controllers
{
    [Route("api/[controller]")]
    [ApiController]
    public class FileController : ControllerBase
    {
        private readonly IHostEnvironment _hostEnvironment;
        
        public FileController(IHostEnvironment hostEnvironment)
        {
            _hostEnvironment = hostEnvironment;
        }

        [HttpGet("{fileName}")]
        public async Task<IActionResult> GetFile([FromRoute] string fileName)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(ModelState);
            }
            
            var uploads = Path.Combine(_hostEnvironment.ContentRootPath, "uploads");
            var fullFilePath = Path.Combine(uploads, fileName);

            if (!System.IO.File.Exists(fullFilePath))
                return NotFound();
            
            var memory = new MemoryStream();
            await using (var stream = new FileStream(fullFilePath, FileMode.Open))
            {
                await stream.CopyToAsync(memory);
            }
            memory.Position = 0;
            
            return File(memory, GetContentType(fileName));
        }
        
        private string GetContentType(string fileName)
        {
            var types = GetMimeTypes();
            var ext = Path.GetExtension(fileName).ToLowerInvariant();
            return types[ext];
        }

        private Dictionary<string, string> GetMimeTypes()
        {
            return new Dictionary<string, string>
            {
                {".txt", "text/plain"},
                {".pdf", "application/pdf"},
                {".doc", "application/vnd.ms-word"},  
                {".docx", "application/vnd.openxmlformats-officedocument.wordprocessingml.document"},  
                {".jpg", "image/jpeg"}, 
                {".png", "image/png"},  
                // include other MIME types as required
            };
        }
    }
}